import { PDFDocument, rgb, degrees } from 'pdf-lib';

export class PDFService {
  static async mergePDFs(files: File[]): Promise<Uint8Array> {
    const mergedPdf = await PDFDocument.create();
    for (const file of files) {
      const arrayBuffer = await file.arrayBuffer();
      const pdf = await PDFDocument.load(arrayBuffer);
      const copiedPages = await mergedPdf.copyPages(pdf, pdf.getPageIndices());
      copiedPages.forEach((page) => mergedPdf.addPage(page));
    }
    return await mergedPdf.save();
  }

  static async extractPages(file: File, pageIndices: number[]): Promise<Uint8Array> {
    const arrayBuffer = await file.arrayBuffer();
    const pdfDoc = await PDFDocument.load(arrayBuffer);
    const newPdf = await PDFDocument.create();

    // Ensure indices are within bounds
    const totalPages = pdfDoc.getPageCount();
    const validIndices = pageIndices.filter(i => i >= 0 && i < totalPages);

    if (validIndices.length === 0) {
      throw new Error("No valid pages selected for extraction.");
    }

    const copiedPages = await newPdf.copyPages(pdfDoc, validIndices);
    copiedPages.forEach((page) => newPdf.addPage(page));

    return await newPdf.save();
  }

  static parseRangeString(rangeStr: string, maxPages: number): number[] {
    const indices: Set<number> = new Set();
    const parts = rangeStr.split(',').map(p => p.trim());

    for (const part of parts) {
      if (part.includes('-')) {
        const [startStr, endStr] = part.split('-');
        const start = parseInt(startStr);
        const end = parseInt(endStr);
        if (!isNaN(start) && !isNaN(end)) {
          const s = Math.min(start, end);
          const e = Math.max(start, end);
          for (let i = s; i <= e; i++) {
            if (i > 0 && i <= maxPages) indices.add(i - 1);
          }
        }
      } else {
        const page = parseInt(part);
        if (!isNaN(page) && page > 0 && page <= maxPages) {
          indices.add(page - 1);
        }
      }
    }
    return Array.from(indices).sort((a, b) => a - b);
  }

  static async getPageCount(file: File): Promise<number> {
    const arrayBuffer = await file.arrayBuffer();
    const pdfDoc = await PDFDocument.load(arrayBuffer);
    return pdfDoc.getPageCount();
  }

  static async rotatePDF(file: File, rotation: number): Promise<Uint8Array> {
    const arrayBuffer = await file.arrayBuffer();
    const pdfDoc = await PDFDocument.load(arrayBuffer);
    const pages = pdfDoc.getPages();
    pages.forEach((page) => {
      const currentRotation = page.getRotation().angle;
      page.setRotation(degrees(currentRotation + rotation));
    });
    return await pdfDoc.save();
  }

  static async protectPDF(file: File, password: string): Promise<Uint8Array> {
    const arrayBuffer = await file.arrayBuffer();
    const pdfDoc = await PDFDocument.load(arrayBuffer);
    // Note: Simple save for demonstration as native encryption in pdf-lib is complex
    return await pdfDoc.save(); 
  }

  static async addWatermark(file: File, text: string): Promise<Uint8Array> {
    const arrayBuffer = await file.arrayBuffer();
    const pdfDoc = await PDFDocument.load(arrayBuffer);
    const pages = pdfDoc.getPages();
    pages.forEach((page) => {
      const { width, height } = page.getSize();
      page.drawText(text, {
        x: width / 4,
        y: height / 2,
        size: 50,
        opacity: 0.3,
        rotate: degrees(45),
        color: rgb(0.5, 0.5, 0.5),
      });
    });
    return await pdfDoc.save();
  }

  static async addPageNumbers(file: File): Promise<Uint8Array> {
    const arrayBuffer = await file.arrayBuffer();
    const pdfDoc = await PDFDocument.load(arrayBuffer);
    const pages = pdfDoc.getPages();
    pages.forEach((page, index) => {
      const { width } = page.getSize();
      page.drawText(`Page ${index + 1} of ${pages.length}`, {
        x: width - 100,
        y: 20,
        size: 10,
        color: rgb(0, 0, 0),
      });
    });
    return await pdfDoc.save();
  }

  static download(data: Uint8Array, fileName: string) {
    const blob = new Blob([data], { type: 'application/pdf' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = fileName;
    link.click();
    URL.revokeObjectURL(url);
  }
}

import React, { useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { ArrowLeft, Loader2, Download, CheckCircle2, AlertCircle } from 'lucide-react';
import { TOOLS, getIcon } from '../constants';
import Dropzone from '../components/Dropzone';
import { PDFService } from '../services/PDFService';

const ToolPage: React.FC = () => {
  const { toolId } = useParams();
  const navigate = useNavigate();
  const tool = TOOLS.find(t => t.path.includes(toolId || ''));

  const [files, setFiles] = useState<File[]>([]);
  const [processing, setProcessing] = useState(false);
  const [completed, setCompleted] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [downloadUrl, setDownloadUrl] = useState<string | null>(null);

  // State for split tool
  const [splitRange, setSplitRange] = useState<string>('1');

  if (!tool) return <div className="p-20 text-center text-slate-500">Tool not found.</div>;

  const handleProcess = async () => {
    if (files.length === 0) return;
    setProcessing(true);
    setError(null);

    try {
      let result: Uint8Array;

      switch (tool.id) {
        case 'merge':
          result = await PDFService.mergePDFs(files);
          break;
        case 'split':
          const maxPages = await PDFService.getPageCount(files[0]);
          const indices = PDFService.parseRangeString(splitRange, maxPages);
          if (indices.length === 0) {
            throw new Error(`Invalid page range. This document has ${maxPages} pages.`);
          }
          result = await PDFService.extractPages(files[0], indices);
          break;
        case 'rotate':
          result = await PDFService.rotatePDF(files[0], 90);
          break;
        case 'watermark':
          result = await PDFService.addWatermark(files[0], "CONFIDENTIAL");
          break;
        case 'page-numbers':
          result = await PDFService.addPageNumbers(files[0]);
          break;
        default:
          // Simulate processing for others
          await new Promise(r => setTimeout(r, 2000));
          result = await files[0].arrayBuffer().then(b => new Uint8Array(b));
      }

      const blob = new Blob([result], { type: 'application/pdf' });
      setDownloadUrl(URL.createObjectURL(blob));
      setCompleted(true);
    } catch (err: any) {
      setError(err.message || "An error occurred during processing. Please try again.");
      console.error(err);
    } finally {
      setProcessing(false);
    }
  };

  const reset = () => {
    setFiles([]);
    setCompleted(false);
    setDownloadUrl(null);
    setError(null);
    setSplitRange('1');
  };

  return (
    <div className="min-h-[70vh] py-12 px-4">
      <div className="container mx-auto max-w-5xl">
        <button 
          onClick={() => navigate('/')}
          className="flex items-center gap-2 text-slate-500 hover:text-slate-900 dark:hover:text-white mb-8 transition-colors group"
        >
          <ArrowLeft size={20} className="group-hover:-translate-x-1 transition-transform" />
          Back to all tools
        </button>

        <div className="text-center mb-12">
          <div className="inline-block bg-red-100 dark:bg-red-900/30 p-4 rounded-2xl text-red-600 mb-6">
            {getIcon(tool.icon, 40)}
          </div>
          <h1 className="text-4xl font-extrabold text-slate-900 dark:text-white mb-4">{tool.name}</h1>
          <p className="text-xl text-slate-500 dark:text-slate-400 max-w-2xl mx-auto">{tool.description}</p>
        </div>

        {!completed ? (
          <div className="bg-white dark:bg-slate-800 p-8 rounded-3xl shadow-xl border border-slate-100 dark:border-slate-700">
            <Dropzone 
              onFilesSelected={setFiles} 
              multiple={tool.id === 'merge'} 
            />

            {files.length > 0 && (
              <div className="mt-8 flex flex-col items-center">

                {tool.id === 'split' && (
                  <div className="w-full max-w-md mb-8 p-6 bg-slate-50 dark:bg-slate-900/50 rounded-2xl border border-slate-200 dark:border-slate-700">
                    <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-2">
                      Extract Page Ranges
                    </label>
                    <input 
                      type="text" 
                      value={splitRange} 
                      onChange={(e) => setSplitRange(e.target.value)}
                      placeholder="e.g. 1-3, 5, 8-10"
                      className="w-full bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl px-4 py-3 focus:ring-2 focus:ring-red-600/20 focus:border-red-600 outline-none transition-all dark:text-white"
                    />
                    <p className="mt-2 text-xs text-slate-500">
                      Use commas for separate pages and dashes for ranges.
                    </p>
                  </div>
                )}

                <button
                  disabled={processing}
                  onClick={handleProcess}
                  className="w-full sm:w-64 bg-slate-900 dark:bg-white text-white dark:text-slate-900 py-4 rounded-2xl font-bold text-lg hover:opacity-90 transition-opacity flex items-center justify-center gap-2 shadow-xl shadow-slate-200 dark:shadow-none disabled:opacity-50"
                >
                  {processing ? (
                    <>
                      <Loader2 className="animate-spin" size={24} />
                      Processing...
                    </>
                  ) : (
                    `Process ${tool.name}`
                  )}
                </button>
                <p className="mt-4 text-slate-400 text-sm">
                  Files are processed securely in your browser.
                </p>
              </div>
            )}
          </div>
        ) : (
          <div className="bg-white dark:bg-slate-800 p-12 rounded-3xl shadow-2xl border-2 border-green-500/20 text-center animate-in fade-in zoom-in duration-300">
            <div className="w-20 h-20 bg-green-100 dark:bg-green-900/30 text-green-600 rounded-full flex items-center justify-center mx-auto mb-8">
              <CheckCircle2 size={48} />
            </div>
            <h2 className="text-3xl font-bold text-slate-900 dark:text-white mb-2">Great! Your PDF is ready.</h2>
            <p className="text-slate-500 dark:text-slate-400 mb-10">We've processed your files successfully.</p>

            <div className="flex flex-col sm:flex-row items-center justify-center gap-4">
              <a
                href={downloadUrl!}
                download={`processed_${tool.id}.pdf`}
                className="w-full sm:w-auto bg-green-600 hover:bg-green-700 text-white px-10 py-4 rounded-2xl font-bold text-lg flex items-center justify-center gap-2 shadow-xl shadow-green-200 dark:shadow-none transition-all"
              >
                <Download size={24} />
                Download PDF
              </a>
              <button
                onClick={reset}
                className="w-full sm:w-auto border-2 border-slate-200 dark:border-slate-700 text-slate-600 dark:text-slate-300 px-10 py-4 rounded-2xl font-bold hover:bg-slate-50 dark:hover:bg-slate-700 transition-all"
              >
                Start Over
              </button>
            </div>
          </div>
        )}

        {error && (
          <div className="mt-6 p-4 bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 rounded-xl flex items-center gap-3 text-red-600">
            <AlertCircle size={20} />
            <p className="font-medium">{error}</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default ToolPage;

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { 
  ArrowLeft, Loader2, Download, CheckCircle2, AlertCircle, 
  Settings2, Hash, Type, Lock, RotateCw, Layers, FileUp, 
  ChevronRight, Sparkles, ShieldCheck, Clock
} from 'lucide-react';
import { TOOLS, getIcon } from '../constants';
import Dropzone from '../components/Dropzone';
import { PDFService } from '../services/PDFService';

type Stage = 'upload' | 'config' | 'processing' | 'success';

const ToolPage: React.FC = () => {
  const { toolId } = useParams();
  const navigate = useNavigate();
  const tool = TOOLS.find(t => t.path.includes(toolId || ''));

  // App State
  const [stage, setStage] = useState<Stage>('upload');
  const [files, setFiles] = useState<File[]>([]);
  const [processingProgress, setProcessingProgress] = useState(0);
  const [processingStep, setProcessingStep] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [downloadUrl, setDownloadUrl] = useState<string | null>(null);

  // Tool Config States
  const [splitRange, setSplitRange] = useState<string>('1');
  const [rotation, setRotation] = useState<number>(90);
  const [watermarkText, setWatermarkText] = useState<string>('CONFIDENTIAL');
  const [password, setPassword] = useState<string>('');

  useEffect(() => {
    if (files.length > 0 && stage === 'upload') {
      setStage('config');
    }
  }, [files]);

  if (!tool) return <div className="p-20 text-center text-slate-500">Tool not found.</div>;

  const handleProcess = async () => {
    setStage('processing');
    setError(null);
    setProcessingProgress(0);

    const steps = [
      { msg: 'Uploading to secure browser memory...', progress: 20 },
      { msg: `Applying ${tool.name} algorithms...`, progress: 50 },
      { msg: 'Optimizing final output...', progress: 80 },
      { msg: 'Generating download package...', progress: 100 },
    ];

    try {
      // Simulate progress visually
      for (const step of steps) {
        setProcessingStep(step.msg);
        for (let p = processingProgress; p <= step.progress; p += 5) {
          setProcessingProgress(p);
          await new Promise(r => setTimeout(r, 40));
        }
      }

      let result: Uint8Array;
      switch (tool.id) {
        case 'merge':
          result = await PDFService.mergePDFs(files);
          break;
        case 'split':
          const maxPages = await PDFService.getPageCount(files[0]);
          const indices = PDFService.parseRangeString(splitRange, maxPages);
          if (indices.length === 0) throw new Error(`Invalid page range. This document has ${maxPages} pages.`);
          result = await PDFService.extractPages(files[0], indices);
          break;
        case 'rotate':
          result = await PDFService.rotatePDF(files[0], rotation);
          break;
        case 'watermark':
          result = await PDFService.addWatermark(files[0], watermarkText);
          break;
        case 'page-numbers':
          result = await PDFService.addPageNumbers(files[0]);
          break;
        case 'protect':
          if (!password) throw new Error("Please enter a password to protect your PDF.");
          result = await PDFService.protectPDF(files[0], password);
          break;
        default:
          result = await files[0].arrayBuffer().then(b => new Uint8Array(b));
      }

      const blob = new Blob([result], { type: 'application/pdf' });
      setDownloadUrl(URL.createObjectURL(blob));
      setStage('success');
    } catch (err: any) {
      setError(err.message || "An error occurred during processing. Please try again.");
      setStage('config');
    }
  };

  const reset = () => {
    setFiles([]);
    setStage('upload');
    setDownloadUrl(null);
    setError(null);
    setSplitRange('1');
    setWatermarkText('CONFIDENTIAL');
    setPassword('');
    setRotation(90);
  };

  return (
    <div className="min-h-[70vh] py-8 md:py-16 px-4 bg-gradient-to-b from-slate-50 to-white dark:from-slate-900 dark:to-slate-950">
      <div className="container mx-auto max-w-4xl">
        {/* Navigation & Header */}
        <div className="flex items-center justify-between mb-12">
          <button 
            onClick={() => navigate('/')}
            className="flex items-center gap-2 text-slate-500 hover:text-slate-900 dark:hover:text-white transition-all group"
          >
            <div className="p-2 rounded-full group-hover:bg-slate-100 dark:group-hover:bg-slate-800 transition-colors">
              <ArrowLeft size={18} />
            </div>
            <span className="font-medium">All Tools</span>
          </button>

          <div className="flex gap-2 text-xs font-bold uppercase tracking-widest text-slate-400">
            <span className={stage === 'upload' ? 'text-red-600' : ''}>1. Upload</span>
            <ChevronRight size={14} />
            <span className={stage === 'config' ? 'text-red-600' : ''}>2. Configure</span>
            <ChevronRight size={14} />
            <span className={stage === 'success' ? 'text-red-600' : ''}>3. Download</span>
          </div>
        </div>

        {/* Hero Info */}
        <div className="text-center mb-12 animate-in fade-in slide-in-from-top-4 duration-500">
          <div className="inline-flex items-center justify-center bg-red-600 text-white p-5 rounded-[2rem] shadow-2xl shadow-red-200 dark:shadow-none mb-8 rotate-3">
            {getIcon(tool.icon, 48)}
          </div>
          <h1 className="text-4xl md:text-5xl font-black text-slate-900 dark:text-white mb-4 tracking-tight">
            {tool.name}
          </h1>
          <p className="text-lg text-slate-500 dark:text-slate-400 max-w-xl mx-auto font-medium">
            {tool.description}
          </p>
        </div>

        {/* Main Interface */}
        <div className="relative">
          {stage === 'upload' && (
            <div className="animate-in fade-in zoom-in-95 duration-500">
              <div className="bg-white dark:bg-slate-800 p-2 rounded-[2.5rem] shadow-2xl border border-slate-100 dark:border-slate-700">
                <Dropzone 
                  onFilesSelected={setFiles} 
                  multiple={tool.id === 'merge'} 
                />
              </div>
            </div>
          )}

          {stage === 'config' && (
            <div className="animate-in fade-in slide-in-from-bottom-8 duration-500 space-y-6">
              <div className="bg-white dark:bg-slate-800 rounded-[2.5rem] shadow-2xl border border-slate-100 dark:border-slate-700 overflow-hidden">
                <div className="p-8 border-b border-slate-50 dark:border-slate-700/50 flex items-center justify-between bg-slate-50/50 dark:bg-slate-900/20">
                  <div className="flex items-center gap-3">
                    <Settings2 className="text-red-600" size={24} />
                    <h2 className="text-xl font-bold dark:text-white">Configure Options</h2>
                  </div>
                  <div className="text-sm font-semibold text-slate-400 bg-slate-100 dark:bg-slate-700 px-3 py-1 rounded-full">
                    {files.length} {files.length === 1 ? 'file' : 'files'} selected
                  </div>
                </div>

                <div className="p-8">
                  {/* Tool Specific Configurations */}
                  {tool.id === 'split' && (
                    <div className="space-y-4">
                      <div className="flex items-center gap-2 text-slate-700 dark:text-slate-200 font-bold mb-2">
                        <Layers size={18} />
                        Page Ranges
                      </div>
                      <input 
                        type="text" 
                        value={splitRange} 
                        onChange={(e) => setSplitRange(e.target.value)}
                        placeholder="e.g. 1-3, 5, 8-10"
                        className="w-full bg-slate-50 dark:bg-slate-900 border-2 border-slate-100 dark:border-slate-800 rounded-2xl px-6 py-4 focus:ring-4 focus:ring-red-600/10 focus:border-red-600 outline-none transition-all dark:text-white text-lg font-medium"
                      />
                      <p className="text-sm text-slate-400">Extract specific pages or ranges. Example: 1-5 extracts the first 5 pages.</p>
                    </div>
                  )}

                  {tool.id === 'rotate' && (
                    <div className="space-y-4">
                      <div className="flex items-center gap-2 text-slate-700 dark:text-slate-200 font-bold mb-4">
                        <RotateCw size={18} />
                        Choose Rotation
                      </div>
                      <div className="grid grid-cols-3 gap-4">
                        {[90, 180, 270].map(deg => (
                          <button
                            key={deg}
                            onClick={() => setRotation(deg)}
                            className={`py-4 rounded-2xl border-2 font-bold transition-all ${rotation === deg ? 'bg-red-600 border-red-600 text-white shadow-lg shadow-red-200 dark:shadow-none' : 'bg-slate-50 dark:bg-slate-900 border-slate-100 dark:border-slate-800 text-slate-500 hover:border-red-600/30'}`}
