              <div className="bg-white dark:bg-slate-800 p-8 rounded-[2rem] border border-slate-100 dark:border-slate-700 mt-12">
                <h3 className="text-2xl font-bold mb-6 dark:text-white">How to {tool.name} in 3 easy steps</h3>
                <div className="space-y-6">
                  <div className="flex gap-4">
                    <div className="flex-shrink-0 w-8 h-8 bg-red-100 text-red-600 rounded-full flex items-center justify-center font-bold">1</div>
                    <p className="text-slate-600 dark:text-slate-400">Select your PDF files from your computer or drag them into the upload area.</p>
                  </div>
                  <div className="flex gap-4">
                    <div className="flex-shrink-0 w-8 h-8 bg-red-100 text-red-600 rounded-full flex items-center justify-center font-bold">2</div>
                    <p className="text-slate-600 dark:text-slate-400">Adjust any specific settings for {tool.name.toLowerCase()} and click the "Process" button.</p>
