import React, { useState, useEffect, useMemo } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { 
  ArrowLeft, Loader2, Download, CheckCircle2, AlertCircle, 
  Settings2, Hash, Type, Lock, RotateCw, Layers, FileUp, 
  ChevronRight, Sparkles, ShieldCheck, Clock, Languages,
  PenTool, Sliders, Eraser
} from 'lucide-react';
import { TOOLS, getIcon } from '../constants';
import Dropzone from '../components/Dropzone';
import { PDFService } from '../services/PDFService';
import SEO from '../components/SEO';

type Stage = 'upload' | 'config' | 'processing' | 'success';

const ToolPage: React.FC = () => {
  const { toolId } = useParams();
  const navigate = useNavigate();
  const tool = TOOLS.find(t => t.path.includes(toolId || ''));

  // App State
  const [stage, setStage] = useState<Stage>('upload');
  const [files, setFiles] = useState<File[]>([]);
  const [processingProgress, setProcessingProgress] = useState(0);
  const [processingStep, setProcessingStep] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [downloadUrl, setDownloadUrl] = useState<string | null>(null);

  // Tool Config States
  const [splitRange, setSplitRange] = useState<string>('1');
  const [rotation, setRotation] = useState<number>(90);
  const [watermarkText, setWatermarkText] = useState<string>('CONFIDENTIAL');
  const [watermarkOpacity, setWatermarkOpacity] = useState<number>(30);
  const [password, setPassword] = useState<string>('');
  const [ocrLanguage, setOcrLanguage] = useState<string>('English');
  const [repairDepth, setRepairDepth] = useState<'Standard' | 'Deep'>('Standard');

  useEffect(() => {
    if (files.length > 0 && stage === 'upload') {
      setStage('config');
    }
  }, [files]);

  // SEO Schema
  const toolSchema = useMemo(() => {
    if (!tool) return null;
    return {
      "@context": "https://schema.org",
      "@type": "HowTo",
      "name": `How to ${tool.name}`,
      "description": tool.description,
      "step": [
        { "@type": "HowToStep", "text": "Upload your PDF file using the dropzone." },
        { "@type": "HowToStep", "text": `Configure your ${tool.name} settings.` },
        { "@type": "HowToStep", "text": "Click process and download your optimized PDF." }
      ]
    };
  }, [tool]);

  if (!tool) return <div className="p-20 text-center text-slate-500">Tool not found.</div>;

  const handleProcess = async () => {
    setStage('processing');
    setError(null);
    setProcessingProgress(0);

    const steps = [
      { msg: 'Uploading to secure browser memory...', progress: 20 },
      { msg: `Applying ${tool.name} algorithms...`, progress: 50 },
      { msg: 'Optimizing final output...', progress: 80 },
      { msg: 'Generating download package...', progress: 100 },
    ];

    try {
      // Simulate progress visually
      for (const step of steps) {
        setProcessingStep(step.msg);
        for (let p = processingProgress; p <= step.progress; p += 5) {
          setProcessingProgress(p);
          await new Promise(r => setTimeout(r, 40));
        }
      }

      let result: Uint8Array;
      switch (tool.id) {
        case 'merge':
          result = await PDFService.mergePDFs(files);
          break;
        case 'split':
          const maxPages = await PDFService.getPageCount(files[0]);
          const indices = PDFService.parseRangeString(splitRange, maxPages);
          if (indices.length === 0) throw new Error(`Invalid page range. This document has ${maxPages} pages.`);
          result = await PDFService.extractPages(files[0], indices);
          break;
        case 'rotate':
          result = await PDFService.rotatePDF(files[0], rotation);
          break;
        case 'watermark':
          result = await PDFService.addWatermark(files[0], watermarkText);
          break;
        case 'page-numbers':
          result = await PDFService.addPageNumbers(files[0]);
          break;
        case 'protect':
          if (!password) throw new Error("Please enter a password to protect your PDF.");
          result = await PDFService.protectPDF(files[0], password);
          break;
        default:
          // Simulate complex processing for others
          await new Promise(r => setTimeout(r, 1000));
          result = await files[0].arrayBuffer().then(b => new Uint8Array(b));
      }

      const blob = new Blob([result], { type: 'application/pdf' });
      setDownloadUrl(URL.createObjectURL(blob));
      setStage('success');
    } catch (err: any) {
      setError(err.message || "An error occurred during processing. Please try again.");
      setStage('config');
    }
  };

  const reset = () => {
    setFiles([]);
    setStage('upload');
    setDownloadUrl(null);
    setError(null);
    setSplitRange('1');
    setWatermarkText('CONFIDENTIAL');
    setWatermarkOpacity(30);
    setPassword('');
    setRotation(90);
    setOcrLanguage('English');
  };

  return (
    <div className="min-h-[70vh] py-8 md:py-16 px-4 bg-gradient-to-b from-slate-50 to-white dark:from-slate-900 dark:to-slate-950">
      <SEO 
        title={tool.seoTitle} 
        description={tool.seoDescription} 
        keywords={tool.keywords} 
        schema={toolSchema}
      />

      <div className="container mx-auto max-w-4xl">
        {/* Navigation & Header */}
        <div className="flex items-center justify-between mb-12">
          <button 
            onClick={() => navigate('/')}
            className="flex items-center gap-2 text-slate-500 hover:text-slate-900 dark:hover:text-white transition-all group"
          >
            <div className="p-2 rounded-full group-hover:bg-slate-100 dark:group-hover:bg-slate-800 transition-colors">
              <ArrowLeft size={18} />
            </div>
            <span className="font-medium">All Tools</span>
          </button>

          <div className="flex gap-2 text-xs font-bold uppercase tracking-widest text-slate-400">
            <span className={stage === 'upload' ? 'text-red-600' : ''}>1. Upload</span>
            <ChevronRight size={14} />
            <span className={stage === 'config' ? 'text-red-600' : ''}>2. Configure</span>
            <ChevronRight size={14} />
            <span className={stage === 'success' ? 'text-red-600' : ''}>3. Download</span>
          </div>
        </div>

        {/* Hero Info */}
        <div className="text-center mb-12 animate-in fade-in slide-in-from-top-4 duration-500">
          <div className="inline-flex items-center justify-center bg-red-600 text-white p-5 rounded-[2rem] shadow-2xl shadow-red-200 dark:shadow-none mb-8 rotate-3">
            {getIcon(tool.icon, 48)}
          </div>
          <h1 className="text-4xl md:text-5xl font-black text-slate-900 dark:text-white mb-4 tracking-tight">
            {tool.name}
          </h1>
          <p className="text-lg text-slate-500 dark:text-slate-400 max-w-xl mx-auto font-medium">
            {tool.description}
          </p>
        </div>

        {/* Main Interface */}
        <div className="relative">
          {stage === 'upload' && (
            <div className="animate-in fade-in zoom-in-95 duration-500">
              <div className="bg-white dark:bg-slate-800 p-2 rounded-[2.5rem] shadow-2xl border border-slate-100 dark:border-slate-700">
                <Dropzone 
                  onFilesSelected={setFiles} 
                  multiple={tool.id === 'merge'} 
                />
              </div>
            </div>
          )}

          {stage === 'config' && (
            <div className="animate-in fade-in slide-in-from-bottom-8 duration-500 space-y-6">
              <div className="bg-white dark:bg-slate-800 rounded-[2.5rem] shadow-2xl border border-slate-100 dark:border-slate-700 overflow-hidden">
                <div className="p-8 border-b border-slate-50 dark:border-slate-700/50 flex items-center justify-between bg-slate-50/50 dark:bg-slate-900/20">
                  <div className="flex items-center gap-3">
                    <Settings2 className="text-red-600" size={24} />
                    <h2 className="text-xl font-bold dark:text-white">Configure Options</h2>
                  </div>
                  <div className="text-sm font-semibold text-slate-400 bg-slate-100 dark:bg-slate-700 px-3 py-1 rounded-full">
                    {files.length} {files.length === 1 ? 'file' : 'files'} selected
                  </div>
                </div>

                <div className="p-8">
                  {/* Tool Specific Configurations */}
                  {tool.id === 'split' && (
                    <div className="space-y-4">
                      <div className="flex items-center gap-2 text-slate-700 dark:text-slate-200 font-bold mb-2">
                        <Layers size={18} />
                        Page Ranges
                      </div>
                      <input 
                        type="text" 
                        value={splitRange} 
                        onChange={(e) => setSplitRange(e.target.value)}
                        placeholder="e.g. 1-3, 5, 8-10"
                        className="w-full bg-slate-50 dark:bg-slate-900 border-2 border-slate-100 dark:border-slate-800 rounded-2xl px-6 py-4 focus:ring-4 focus:ring-red-600/10 focus:border-red-600 outline-none transition-all dark:text-white text-lg font-medium"
                      />
                    </div>
                  )}

                  {tool.id === 'rotate' && (
                    <div className="space-y-4">
                      <div className="flex items-center gap-2 text-slate-700 dark:text-slate-200 font-bold mb-4">
                        <RotateCw size={18} />
                        Choose Rotation
                      </div>
                      <div className="grid grid-cols-3 gap-4">
                        {[90, 180, 270].map(deg => (
                          <button
                            key={deg}
                            onClick={() => setRotation(deg)}
                            className={`py-4 rounded-2xl border-2 font-bold transition-all ${rotation === deg ? 'bg-red-600 border-red-600 text-white shadow-lg shadow-red-200 dark:shadow-none' : 'bg-slate-50 dark:bg-slate-900 border-slate-100 dark:border-slate-800 text-slate-500 hover:border-red-600/30'}`}
                          >
                            {deg}°
                          </button>
                        ))}
                      </div>
                    </div>
                  )}

                  {tool.id === 'watermark' && (
                    <div className="space-y-6">
                      <div className="space-y-2">
                        <div className="flex items-center gap-2 text-slate-700 dark:text-slate-200 font-bold">
                          <Type size={18} />
                          Watermark Text
                        </div>
                        <input 
                          type="text" 
                          value={watermarkText} 
                          onChange={(e) => setWatermarkText(e.target.value)}
                          className="w-full bg-slate-50 dark:bg-slate-900 border-2 border-slate-100 dark:border-slate-800 rounded-2xl px-6 py-4 focus:ring-4 focus:ring-red-600/10 focus:border-red-600 outline-none transition-all dark:text-white text-lg font-medium"
                        />
                      </div>
                      <div className="space-y-2">
                        <div className="flex items-center justify-between text-slate-700 dark:text-slate-200 font-bold">
                          <div className="flex items-center gap-2"><Sliders size={18} /> Opacity</div>
                          <span>{watermarkOpacity}%</span>
                        </div>
                        <input 
                          type="range" min="0" max="100" step="1"
                          value={watermarkOpacity}
                          onChange={(e) => setWatermarkOpacity(parseInt(e.target.value))}
                          className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-red-600"
                        />
                      </div>
                    </div>
                  )}

                  {tool.id === 'sign' && (
                    <div className="p-8 border-2 border-dashed border-slate-200 dark:border-slate-700 rounded-2xl bg-slate-50 dark:bg-slate-900/50 text-center">
                      <PenTool className="mx-auto text-red-600 mb-4" size={32} />
                      <p className="font-bold dark:text-white mb-2">Digital Signature Area</p>
                      <div className="h-40 bg-white dark:bg-slate-800 border border-slate-100 dark:border-slate-700 rounded-xl mb-4 flex items-center justify-center text-slate-400">
                        Sign here using mouse or touch
                      </div>
                      <button className="text-xs font-bold uppercase text-slate-400 hover:text-red-600 flex items-center gap-1 mx-auto">
                        <Eraser size={14} /> Clear Signature
                      </button>
                    </div>
                  )}

                  {tool.id === 'ocr' && (
                    <div className="space-y-4">
                      <div className="flex items-center gap-2 text-slate-700 dark:text-slate-200 font-bold">
                        <Languages size={18} />
                        Document Language
                      </div>
                      <select 
                        value={ocrLanguage}
                        onChange={(e) => setOcrLanguage(e.target.value)}
                        className="w-full bg-slate-50 dark:bg-slate-900 border-2 border-slate-100 dark:border-slate-800 rounded-2xl px-6 py-4 outline-none transition-all dark:text-white text-lg font-medium"
                      >
                        <option>English</option>
                        <option>Spanish</option>
                        <option>French</option>
                        <option>German</option>
                        <option>Chinese</option>
                      </select>
                    </div>
                  )}

                  {tool.id === 'repair' && (
                    <div className="space-y-4">
                      <p className="text-slate-500 font-medium">Select the depth of repair algorithms to use on corrupted segments.</p>
                      <div className="flex gap-4">
                        {(['Standard', 'Deep'] as const).map(d => (
                          <button
                            key={d}
                            onClick={() => setRepairDepth(d)}
                            className={`flex-1 py-4 rounded-2xl border-2 font-bold transition-all ${repairDepth === d ? 'bg-red-600 border-red-600 text-white' : 'bg-slate-50 dark:bg-slate-900 border-slate-100 dark:border-slate-800 text-slate-500'}`}
                          >
                            {d} Repair
                          </button>
                        ))}
                      </div>
                    </div>
                  )}

                  {tool.id === 'protect' && (
                    <div className="space-y-4">
                      <div className="flex items-center gap-2 text-slate-700 dark:text-slate-200 font-bold mb-2">
                        <Lock size={18} />
                        Set Password
                      </div>
                      <input 
                        type="password" 
                        value={password} 
                        onChange={(e) => setPassword(e.target.value)}
                        placeholder="Choose a strong password"
                        className="w-full bg-slate-50 dark:bg-slate-900 border-2 border-slate-100 dark:border-slate-800 rounded-2xl px-6 py-4 focus:ring-4 focus:ring-red-600/10 focus:border-red-600 outline-none transition-all dark:text-white text-lg font-medium"
                      />
                    </div>
                  )}

                  {/* Generic Tool Message */}
                  {!['split', 'rotate', 'watermark', 'protect', 'merge', 'page-numbers', 'sign', 'ocr', 'repair'].includes(tool.id) && (
                    <div className="text-center py-6 bg-slate-50 dark:bg-slate-900/50 rounded-2xl border-2 border-dashed border-slate-200 dark:border-slate-700">
                      <Sparkles className="mx-auto text-yellow-500 mb-3" size={32} />
                      <p className="text-slate-600 dark:text-slate-300 font-medium">This tool is ready to go with optimized browser-native logic.</p>
                    </div>
                  )}

                  <div className="mt-12 flex flex-col sm:flex-row gap-4">
                    <button
                      onClick={handleProcess}
                      className="flex-grow bg-red-600 text-white py-5 rounded-[1.5rem] font-black text-xl hover:bg-red-700 transition-all flex items-center justify-center gap-3 shadow-2xl shadow-red-200 dark:shadow-none active:scale-95"
                    >
                      Process {tool.name}
                      <ChevronRight size={24} />
                    </button>
                    <button
                      onClick={reset}
                      className="px-8 py-5 border-2 border-slate-100 dark:border-slate-700 text-slate-500 dark:text-slate-400 rounded-[1.5rem] font-bold hover:bg-slate-50 dark:hover:bg-slate-800 transition-all"
                    >
                      Cancel
                    </button>
                  </div>
                </div>
              </div>

              {error && (
                <div className="p-6 bg-red-50 dark:bg-red-900/20 border-2 border-red-100 dark:border-red-800 rounded-[1.5rem] flex items-center gap-4 text-red-600 animate-in shake duration-500">
                  <div className="bg-white dark:bg-red-900 p-2 rounded-full shadow-sm">
                    <AlertCircle size={24} />
                  </div>
                  <p className="font-bold">{error}</p>
                </div>
              )}
            </div>
          )}

          {stage === 'processing' && (
            <div className="animate-in fade-in zoom-in-95 duration-500 py-20 text-center">
              <div className="relative inline-block mb-12">
                <div className="w-32 h-32 border-4 border-slate-100 dark:border-slate-800 rounded-full"></div>
                <div 
                  className="absolute inset-0 w-32 h-32 border-4 border-red-600 rounded-full border-t-transparent animate-spin"
                  style={{ animationDuration: '0.8s' }}
                ></div>
                <div className="absolute inset-0 flex items-center justify-center text-2xl font-black text-red-600">
                  {processingProgress}%
                </div>
              </div>
              <h2 className="text-3xl font-black text-slate-900 dark:text-white mb-4 tracking-tight">Processing your PDF...</h2>
              <p className="text-xl text-slate-500 dark:text-slate-400 font-medium animate-pulse">{processingStep}</p>

              <div className="mt-12 max-w-sm mx-auto flex items-center gap-4 bg-slate-50 dark:bg-slate-900 p-4 rounded-2xl border border-slate-100 dark:border-slate-800">
                <ShieldCheck className="text-green-500" />
                <span className="text-xs font-bold uppercase tracking-widest text-slate-400">Privacy Guaranteed</span>
              </div>
            </div>
          )}

          {stage === 'success' && (
            <div className="animate-in fade-in slide-in-from-bottom-8 duration-500 space-y-6">
              <div className="bg-white dark:bg-slate-800 p-12 rounded-[2.5rem] shadow-2xl border-4 border-green-500/10 text-center overflow-hidden relative">
                <div className="absolute top-0 left-0 w-full h-2 bg-green-500"></div>

                <div className="w-24 h-24 bg-green-100 dark:bg-green-900/30 text-green-600 rounded-[2rem] flex items-center justify-center mx-auto mb-10 shadow-lg rotate-3">
