                  <div className="p-4 bg-slate-50 dark:bg-slate-900/50 rounded-2xl border border-slate-100 dark:border-slate-800 text-left">
                    <p className="text-xs font-bold uppercase text-slate-400 mb-1">Auto-Delete</p>
                    <p className="text-slate-600 dark:text-slate-300 font-bold flex items-center gap-1"><Clock size={14}/> 2 Hours</p>
