                </div>

                <div className="flex flex-col sm:flex-row items-center justify-center gap-6">
                  <a
                    href={downloadUrl!}
                    download={`PDFMaster_${tool.id}.pdf`}
                    className="w-full sm:w-auto bg-slate-900 dark:bg-white text-white dark:text-slate-900 px-12 py-5 rounded-[1.5rem] font-black text-xl flex items-center justify-center gap-3 shadow-2xl hover:scale-105 transition-all active:scale-95"
                  >
                    <Download size={28} />
                    Download File
                  </a>
                  <button
                    onClick={reset}
                    className="w-full sm:w-auto px-12 py-5 border-2 border-slate-100 dark:border-slate-700 text-slate-600 dark:text-slate-300 rounded-[1.5rem] font-bold text-lg hover:bg-slate-50 dark:hover:bg-slate-800 transition-all"
                  >
                    Process Another
                  </button>
                </div>
              </div>

              {/* Instructional SEO Content */}
              <div className="bg-white dark:bg-slate-800 p-8 rounded-[2rem] border border-slate-100 dark:border-slate-700 mt-12">
                <h3 className="text-2xl font-bold mb-6 dark:text-white">How to {tool.name} in 3 easy steps</h3>
                <div className="space-y-6">
                  <div className="flex gap-4">
                    <div className="flex-shrink-0 w-8 h-8 bg-red-100 text-red-600 rounded-full flex items-center justify-center font-bold">1</div>
                    <p className="text-slate-600 dark:text-slate-400">Select your PDF files from your computer or drag them into the upload area.</p>
                  </div>
                  <div className="flex gap-4">
                    <div className="flex-shrink-0 w-8 h-8 bg-red-100 text-red-600 rounded-full flex items-center justify-center font-bold">2</div>
                    <p className="text-slate-600 dark:text-slate-400">Adjust any specific settings for {tool.name.toLowerCase()} and click the "Process" button.</p>
                  </div>
                  <div className="flex gap-4">
                    <div className="flex-shrink-0 w-8 h-8 bg-red-100 text-red-600 rounded-full flex items-center justify-center font-bold">3</div>
                    <p className="text-slate-600 dark:text-slate-400">Wait a few seconds for our local engine to process your file, then hit download!</p>
                  </div>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
