import React, { useState, useEffect, useMemo } from 'react';
import { useParams, useNavigate, Link } from 'react-router-dom';
import { 
  ArrowLeft, Loader2, Download, CheckCircle2, AlertCircle, 
  Settings2, Lock, RotateCw, Layers, ChevronRight, Sparkles, ShieldCheck, Clock, FileText, Check, RefreshCw
} from 'lucide-react';
import { TOOLS, getIcon } from '../constants.tsx';
import Dropzone from '../components/Dropzone.tsx';
import { PDFService } from '../services/PDFService.ts';
import SEO from '../components/SEO.tsx';
import { useAuth } from '../components/AuthContext.tsx';

type Stage = 'upload' | 'config' | 'processing' | 'success';

const ToolPage: React.FC = () => {
  const { toolId } = useParams();
  const navigate = useNavigate();
  const { user, addHistory } = useAuth();
  const tool = TOOLS.find(t => t.path.includes(toolId || ''));

  const [stage, setStage] = useState<Stage>('upload');
  const [files, setFiles] = useState<File[]>([]);
  const [processingProgress, setProcessingProgress] = useState(0);
  const [processingStep, setProcessingStep] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [downloadUrl, setDownloadUrl] = useState<string | null>(null);
  const [splitRange, setSplitRange] = useState<string>('1');
  const [rotation, setRotation] = useState<number>(90);
  const [watermarkText, setWatermarkText] = useState<string>('CONFIDENTIAL');
  const [watermarkOpacity, setWatermarkOpacity] = useState<number>(30);
  const [password, setPassword] = useState<string>('');

  useEffect(() => {
    if (files.length > 0 && stage === 'upload') {
      setStage('config');
    }
  }, [files, stage]);

  if (!tool) return <div className="p-20 text-center text-slate-500 font-bold">Tool not found.</div>;

  const handleProcess = async () => {
    if (!user) {
      setError("Please log in to process files. It's 100% free!");
      return;
    }

    setStage('processing');
    setError(null);
    setProcessingProgress(0);

    try {
      setProcessingStep('Initializing local engine...');
      let result: Uint8Array;
      switch (tool.id) {
        case 'merge':
          result = await PDFService.mergePDFs(files);
          break;
        case 'split':
          const maxPages = await PDFService.getPageCount(files[0]);
          const indices = PDFService.parseRangeString(splitRange, maxPages);
          result = await PDFService.extractPages(files[0], indices);
          break;
        case 'jpg-to-pdf':
          result = await PDFService.jpgToPdf(files);
          break;
        case 'compress':
          result = await PDFService.compressPDF(files[0]);
          break;
        case 'rotate':
          result = await PDFService.rotatePDF(files[0], rotation);
          break;
        default:
          result = await files[0].arrayBuffer().then(b => new Uint8Array(b));
      }

      setProcessingProgress(100);
      const blob = new Blob([result], { type: 'application/pdf' });
      setDownloadUrl(URL.createObjectURL(blob));
      setStage('success');
      addHistory({ tool: tool.id, fileName: files[0]?.name || `${tool.name}.pdf`, status: 'completed' });
    } catch (err: any) {
      setError(err.message || "An error occurred.");
      setStage('config');
    }
  };

  return (
    <div className="min-h-[80vh] py-8 md:py-16 px-4 bg-slate-50 dark:bg-slate-900 transition-colors">
      <SEO title={tool.seoTitle} description={tool.seoDescription} />
      <div className="container mx-auto max-w-5xl">
        {stage === 'upload' && (
          <div className="bg-white dark:bg-slate-800 p-3 rounded-[2.5rem] shadow-2xl border border-slate-100 dark:border-slate-700">
            <Dropzone 
              onFilesSelected={setFiles} 
              multiple={tool.id === 'merge' || tool.id === 'jpg-to-pdf'} 
              accept={tool.id === 'jpg-to-pdf' ? ".jpg,.jpeg,.png" : ".pdf"}
            />
          </div>
        )}
        {stage === 'config' && (
          <div className="bg-white dark:bg-slate-800 rounded-[2.5rem] p-8 shadow-xl border border-slate-100">
            <h2 className="text-2xl font-black mb-8 dark:text-white">Configure {tool.name}</h2>
            <button onClick={handleProcess} className="w-full bg-red-600 text-white py-5 rounded-2xl font-black text-xl">Process PDF</button>
          </div>
        )}
        {stage === 'success' && (
          <div className="text-center p-12 bg-white dark:bg-slate-800 rounded-[3rem] shadow-2xl">
            <CheckCircle2 size={80} className="mx-auto text-green-500 mb-6" />
            <h2 className="text-4xl font-black mb-4 dark:text-white">Ready to Download!</h2>
            <a href={downloadUrl!} download="output.pdf" className="inline-block bg-slate-900 dark:bg-white text-white dark:text-slate-900 px-12 py-5 rounded-2xl font-black text-xl">Download PDF</a>
          </div>
        )}
      </div>
    </div>
  );
};

